import React, { useState, useContext, useMemo, useEffect } from "react";
import axios from "axios";
import GeneralContext from "./GeneralContext";
import "./BuyActionWindow.css";

const API_URL = process.env.REACT_APP_API_URL || "http://localhost:3002";

const BuyActionWindow = ({ uid, currentPrice = 0 }) => {
  const { closeBuyWindow, refreshDashboard } = useContext(GeneralContext);

  const [mode, setMode] = useState("BUY");
  const [stockQuantity, setStockQuantity] = useState(1);
  const [stockPrice, setStockPrice] = useState(currentPrice);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  // Autofill price if currentPrice changes
  useEffect(() => {
    setStockPrice(currentPrice);
  }, [currentPrice]);

  // Dynamic calculation
  const totalAmount = useMemo(() => {
    return stockQuantity * stockPrice;
  }, [stockQuantity, stockPrice]);

  const handleSubmit = async () => {
    setError("");

    if (!uid) {
      setError("Stock not selected.");
      return;
    }

    if (stockQuantity <= 0 || stockPrice <= 0) {
      setError("Quantity and price must be greater than 0.");
      return;
    }

    try {
      setLoading(true);

      await axios.post(`${API_URL}/newOrder`, {
        name: uid,
        qty: Number(stockQuantity),
        price: Number(stockPrice),
        mode,
      });

      // Refresh dashboard
      if (refreshDashboard) refreshDashboard();

      closeBuyWindow();
    } catch (err) {
      setError(
        err.response?.data?.error || "Transaction failed. Try again."
      );
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="container" id="trade-window">

      <div className="regular-order">
        <h3 style={{ marginBottom: "20px" }}>
          {mode} {uid}
        </h3>

        {/* Mode Toggle */}
        <div style={{ marginBottom: "15px" }}>
          <button
            className={`btn ${mode === "BUY" ? "btn-blue" : "btn-grey"}`}
            onClick={() => setMode("BUY")}
            disabled={loading}
          >
            Buy
          </button>

          <button
            className={`btn ${mode === "SELL" ? "btn-blue" : "btn-grey"}`}
            onClick={() => setMode("SELL")}
            disabled={loading}
          >
            Sell
          </button>
        </div>

        <div className="inputs">
          <fieldset>
            <legend>Qty.</legend>
            <input
              type="number"
              min="1"
              value={stockQuantity}
              onChange={(e) => setStockQuantity(Number(e.target.value))}
              disabled={loading}
            />
          </fieldset>

          <fieldset>
            <legend>Price</legend>
            <input
              type="number"
              step="0.05"
              min="0.05"
              value={stockPrice}
              onChange={(e) => setStockPrice(Number(e.target.value))}
              disabled={loading}
            />
          </fieldset>
        </div>

        {/* Dynamic Total */}
        <div style={{ marginTop: "15px", fontWeight: "600" }}>
          Total: ₹{totalAmount.toLocaleString("en-IN")}
        </div>

        {error && (
          <div style={{ color: "red", marginTop: "10px" }}>
            {error}
          </div>
        )}
      </div>

      <div className="buttons">
        <span>
          Required: ₹{totalAmount.toLocaleString("en-IN")}
        </span>

        <div>
          <button
            className="btn btn-blue"
            onClick={handleSubmit}
            disabled={loading}
          >
            {loading ? "Processing..." : mode}
          </button>

          <button
            className="btn btn-grey"
            onClick={closeBuyWindow}
            disabled={loading}
          >
            Cancel
          </button>
        </div>
      </div>
    </div>
  );
};

export default BuyActionWindow;
